const finishRuntimeCanceledAttempt = `-- name: FinishRuntimeCanceledAttempt :one
UPDATE run_attempts a
SET finished_at = clock_timestamp(), outcome = 'canceled',
    error_code = $1, error_detail_redacted = NULL
WHERE a.run_id = $2
  AND a.id = $3
  AND a.lease_id = $4
  AND a.fencing_token = $5
  AND a.executor_type = 'runtime'
  AND a.finished_at IS NULL
  AND a.outcome IS NULL
  AND a.result_id IS NULL
  AND EXISTS (
      SELECT 1
      FROM runs r
      JOIN run_cancellations c ON c.run_id = r.id AND c.id = r.cancel_request_id
      WHERE r.id = a.run_id
        AND r.runtime_contract_id = 'openlinker.runtime.v2'
        AND r.status = 'canceled'
        AND r.dispatch_state = 'terminal'
        AND c.target_attempt_id = a.id
        AND (
            c.state IN ('stopped', 'unconfirmed')
            OR (
                c.state IN ('unsupported', 'failed')
                AND c.error_code IS NOT NULL
                AND c.requested_at
                    + ($6::bigint * INTERVAL '1 millisecond')
                    <= clock_timestamp()
            )
        )
  )
RETURNING *`

